42	function SuiteIdentity({
43	  suite,
44	  conn,
45	  size = 40,
46	  selected = false,
47	  showDescription = false,
48	}: {
49	  suite: Suite;
50	  conn: Connection | undefined;
51	  size?: number;
52	  selected?: boolean;
53	  showDescription?: boolean;
54	}) {
55	  return (
56	    <Flex
