78	          </Typography.Text>
79	        )}
80	        {showDescription && suite.description && (
81	          <Typography.Paragraph
82	            type="secondary"
83	            ellipsis={{ rows: 2 }}
84	            style={{ fontSize: 12, margin: 0, marginTop: 2 }}
85	          >
86	            {suite.description}
87	          </Typography.Paragraph>
88	        )}
89	      </Flex>
90	    </Flex>
91	  );
92	}
