94	export function Suites() {
95	  const navigate = useNavigate();
96	  // The selected suite is the route (`/suites/:suiteId`) so it deep-links and
97	  // survives the round-trip to the check editor; `/suites` selects nothing.
98	  const { suiteId } = useParams<{ suiteId: string }>();
99	  const selectedId = suiteId ?? null;
100	  const { state, reload } = useAsyncData(listSuites);
101	  const { state: connState } = useAsyncData(listConnections);
102	  // `drawer.suite === undefined` while open = create mode; a suite = edit.
103	  const [drawer, setDrawer] = useState<{ open: boolean; suite?: Suite }>({ open: false });
104	  const [importOpen, setImportOpen] = useState(false);
105	
106	  const connections = connState.status === 'ok' ? connState.data : [];
107	  // A suite binds to a datasource only — creating/importing needs at least one
108	  // (orchestration providers don't count; CLAUDE.md §4, #242).
109	  const hasDatasource = connections.some((c) => CONNECTION_KIND[c.type] === 'datasource');
110	
111	  return (
112	    <Flex vertical gap={24}>
113	      <Flex justify="space-between" align="center" gap={12}>
114	        <Typography.Title level={3} style={{ margin: 0 }}>
115	          Suites
116	        </Typography.Title>
117	        <Flex gap={8}>
118	          <Button
119	            loading={connState.status === 'loading'}
120	            disabled={!hasDatasource}
121	            onClick={() => setImportOpen(true)}
122	          >
123	            Import
124	          </Button>
125	          <Button
126	            type="primary"
127	            loading={connState.status === 'loading'}
128	            disabled={!hasDatasource}
129	            onClick={() => setDrawer({ open: true })}
130	          >
131	            New suite
132	          </Button>
133	        </Flex>
134	      </Flex>
135	      {connState.status === 'error' && (
136	        // Suites can still be viewed/deleted, but creating one needs the
137	        // connection list — surface the failure rather than silently disabling.
138	        <Alert
139	          type="warning"
140	          showIcon
141	          title="Couldn’t load connections"
142	          description={`Creating a suite is unavailable until connections load. ${connState.error}`}
143	        />
144	      )}
145	      <SuitesBody
146	        state={state}
147	        connections={connections}
148	        selectedId={selectedId}
149	        onSelect={(id) => navigate(`/suites/${id}`)}
150	        onEdit={(suite) => setDrawer({ open: true, suite })}
151	        onDeleted={() => {
152	          navigate('/suites');
153	          reload();
154	        }}
155	      />
156	      <SuiteDrawer
157	        open={drawer.open}
158	        suite={drawer.suite}
159	        connections={connections}
160	        onClose={() => setDrawer({ open: false })}
161	        onSaved={() => {
162	          setDrawer({ open: false });
163	          reload();
164	        }}
165	      />
166	      <ImportSuiteDrawer
167	        open={importOpen}
168	        connections={connections}
169	        onClose={() => setImportOpen(false)}
170	        onImported={(suite) => {
171	          setImportOpen(false);
172	          reload();
173	          navigate(`/suites/${suite.id}`);
174	        }}
175	      />
176	    </Flex>
177	  );
178	}
