180	function SuitesBody({
181	  state,
182	  connections,
183	  selectedId,
184	  onSelect,
185	  onEdit,
186	  onDeleted,
187	}: {
188	  state: AsyncState<Suite[]>;
189	  connections: Connection[];
190	  selectedId: string | null;
191	  onSelect: (id: string) => void;
192	  onEdit: (suite: Suite) => void;
193	  onDeleted: () => void;
194	}) {
195	  if (state.status === 'loading') {
196	    return <Spin tip="Loading suites…" size="large" style={{ marginTop: 80 }} />;
197	  }
198	  if (state.status === 'error') {
199	    return (
200	      <Alert
201	        type="error"
202	        showIcon
203	        title="Failed to load suites"
204	        description={state.error}
205	        style={{ margin: 24 }}
206	      />
207	    );
208	  }
209	  const suites = state.data;
210	  if (suites.length === 0) {
211	    return <Empty description="No suites yet — create one to start authoring checks." />;
212	  }
213	  const selected = suites.find((s) => s.id === selectedId) ?? null;
214	
215	  // Nothing selected → a full-width grid of suite cards that fills the page,
216	  // rather than a narrow list beside a big empty panel. Picking one switches to
217	  // the focused master-detail (the list stays, for quick switching).
218	  if (!selected) {
219	    return <SuiteGrid suites={suites} connections={connections} onSelect={onSelect} />;
220	  }
221	
222	  return (
223	    <Flex gap={24} align="flex-start">
224	      <Card size="small" style={{ width: 320, flexShrink: 0 }} styles={{ body: { padding: 0 } }}>
225	        <List
226	          dataSource={suites}
227	          renderItem={(suite) => {
228	            const conn = connections.find((c) => c.id === suite.connection_id);
229	            const isSelected = suite.id === selectedId;
230	            return (
231	              <List.Item
232	                onClick={() => onSelect(suite.id)}
233	                className="dq-suite-row"
234	                style={{
235	                  cursor: 'pointer',
236	                  padding: '12px 16px',
237	                  background: isSelected ? BRAND.selectedBg : undefined,
238	                }}
239	              >
240	                <SuiteIdentity suite={suite} conn={conn} size={34} selected={isSelected} />
241	              </List.Item>
242	            );
243	          }}
244	        />
245	      </Card>
246	      <div style={{ flex: 1, minWidth: 0 }}>
247	        <SuiteDetail
248	          key={selected.id}
249	          suite={selected}
250	          connections={connections}
251	          onEdit={() => onEdit(selected)}
252	          onDeleted={onDeleted}
253	        />
254	      </div>
255	    </Flex>
256	  );
257	}
