259	/** Browse view: suite cards in a responsive grid that fills the page width. */
260	function SuiteGrid({
261	  suites,
262	  connections,
263	  onSelect,
264	}: {
265	  suites: Suite[];
266	  connections: Connection[];
267	  onSelect: (id: string) => void;
268	}) {
269	  return (
270	    <div
271	      style={{
272	        display: 'grid',
273	        gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
274	        gap: 16,
275	      }}
276	    >
277	      {suites.map((suite) => {
278	        const conn = connections.find((c) => c.id === suite.connection_id);
279	        return (
