281	            key={suite.id}
282	            size="small"
283	            className="dq-card--interactive"
284	            style={{ cursor: 'pointer' }}
285	            onClick={() => onSelect(suite.id)}
286	          >
287	            <SuiteIdentity suite={suite} conn={conn} showDescription />
288	          </Card>
289	        );
290	      })}
291	    </div>
292	  );
