295	function SuiteDetail({
296	  suite,
297	  connections,
298	  onEdit,
299	  onDeleted,
300	}: {
301	  suite: Suite;
302	  connections: Connection[];
303	  onEdit: () => void;
304	  onDeleted: () => void;
305	}) {
306	  const { message, modal } = App.useApp();
307	  const navigate = useNavigate();
308	  // Remounted (keyed by suite.id) when the selection changes → checks refetch.
309	  const { state, reload } = useAsyncData(() => listChecks(suite.id));
310	  const connection = connections.find((c) => c.id === suite.connection_id);
311	  // The edit drawer (create is the dedicated /checks/new page) → open iff editing.
312	  const [editingCheck, setEditingCheck] = useState<Check | null>(null);
313	
314	  const [exporting, setExporting] = useState(false);
315	  const [shareOpen, setShareOpen] = useState(false);
316	  const [running, setRunning] = useState(false);
317	  // Managing shares (and deleting) needs admin; the read stamps the caller's level.
318	  const canManage = suite.my_permission === 'owner' || suite.my_permission === 'admin';
319	  // Triggering a run is edit-gated (matches the backend); a null target isn't runnable.
320	  const canRun = canManage || suite.my_permission === 'edit';
321	
322	  // Ref guard (not just `running` state) so a synchronous double-click can't
323	  // dispatch two runs in the render-tick before `loading` disables the button.
324	  const runningRef = useRef(false);
325	  const onRun = async () => {
326	    if (runningRef.current) return;
327	    runningRef.current = true;
328	    setRunning(true);
329	    try {
330	      await runSuite(suite.id);
331	      message.success(`${suite.name}: run queued`);
332	      navigate('/results');
333	    } catch (err) {
334	      message.error(`Run failed: ${err instanceof Error ? err.message : 'unknown error'}`);
335	    } finally {
336	      runningRef.current = false;
337	      setRunning(false);
338	    }
339	  };
340	
341	  const onExport = async () => {
342	    setExporting(true);
343	    try {
344	      const doc = await exportSuite(suite.id);
345	      downloadJson(`${toFilenameStem(suite.name)}.json`, doc);
346	    } catch (err) {
347	      message.error(`Export failed: ${err instanceof Error ? err.message : 'unknown error'}`);
348	    } finally {
349	      setExporting(false);
350	    }
351	  };
352	
353	  const onDelete = () => {
354	    modal.confirm({
355	      title: `Delete “${suite.name}”?`,
356	      content: 'This removes the suite and all of its checks.',
357	      okText: 'Delete',
358	      okType: 'danger',
359	      onOk: async () => {
360	        try {
361	          await deleteSuite(suite.id);
362	          message.success(`${suite.name} deleted`);
363	          onDeleted();
364	        } catch (err) {
365	          message.error(`Delete failed: ${err instanceof Error ? err.message : 'unknown error'}`);
366	          throw err; // keep the confirm modal open on failure
367	        }
368	      },
369	    });
370	  };
371	
372	  return (
373	    <Flex vertical gap={16}>
374	      <Flex justify="space-between" align="flex-start" gap={12}>
375	        <Flex vertical gap={6}>
376	          <Typography.Title level={4} style={{ margin: 0 }}>
377	            {suite.name}
378	          </Typography.Title>
379	          {connection ? (
380	            <Flex gap={8} align="center">
381	              <Typography.Text type="secondary">
382	                {connection.name} · {CONNECTION_TYPE_LABELS[connection.type]}
383	              </Typography.Text>
384	              <Tag color={ENV_COLORS[connection.env]}>{envLabel(connection.env)}</Tag>
385	            </Flex>
386	          ) : (
387	            <Typography.Text type="secondary">Connection {suite.connection_id}</Typography.Text>
388	          )}
389	        </Flex>
390	        <Flex gap={8}>
391	          {canRun &&
392	            (suite.target ? (
393	              <Button
394	                type="primary"
395	                icon={<PlayCircleOutlined />}
396	                loading={running}
397	                onClick={onRun}
398	              >
399	                Run
400	              </Button>
401	            ) : (
402	              // No target yet → not runnable; show why rather than a 422 on click.
403	              // The <span> is required: a disabled antd Button has pointer-events:
404	              // none, so the Tooltip must hover the wrapper, not the button.
405	              <Tooltip title="Set a run target (Edit) before running this suite">
406	                <span style={{ cursor: 'not-allowed' }}>
407	                  <Button type="primary" icon={<PlayCircleOutlined />} disabled>
408	                    Run
409	                  </Button>
410	                </span>
411	              </Tooltip>
412	            ))}
413	          <Button onClick={() => setShareOpen(true)}>Share</Button>
414	          <Button loading={exporting} onClick={onExport}>
415	            Export
416	          </Button>
417	          <Button onClick={onEdit}>Edit</Button>
418	          <Button danger onClick={onDelete}>
419	            Delete
420	          </Button>
421	        </Flex>
422	      </Flex>
423	      {suite.description && <Typography.Paragraph>{suite.description}</Typography.Paragraph>}
424	      <ChecksList
425	        suiteId={suite.id}
426	        state={state}
427	        onAdd={() => navigate(`/suites/${suite.id}/checks/new`)}
428	        onEdit={(check) => setEditingCheck(check)}
429	        onChanged={reload}
430	      />
431	      {/* Triggers are edit-gated (same as runs): a pipeline/DAG bound here runs
432	          the suite on its success. canRun is exactly the edit-level capability. */}
433	      <TriggersPanel suiteId={suite.id} canManage={canRun} />
434	      <CheckDrawer
435	        open={editingCheck !== null}
436	        suiteId={suite.id}
437	        check={editingCheck ?? undefined}
438	        target={suite.target}
439	        onClose={() => setEditingCheck(null)}
440	        onSaved={() => {
441	          setEditingCheck(null);
442	          reload();
443	        }}
444	      />
445	      <SharePanel
446	        open={shareOpen}
447	        suiteId={suite.id}
448	        ownerId={suite.created_by}
449	        canManage={canManage}
450	        onClose={() => setShareOpen(false)}
451	      />
452	    </Flex>
453	  );
454	}
455	
456	function ChecksList({
457	  suiteId,
458	  state,
459	  onAdd,
460	  onEdit,
461	  onChanged,
462	}: {
463	  suiteId: string;
464	  state: AsyncState<Check[]>;
465	  onAdd: () => void;
466	  onEdit: (check: Check) => void;
467	  onChanged: () => void;
468	}) {
469	  const { message, modal } = App.useApp();
470	
471	  const onDelete = (check: Check) => {
472	    modal.confirm({
473	      title: `Delete “${check.name}”?`,
474	      okText: 'Delete',
475	      okType: 'danger',
476	      onOk: async () => {
477	        try {
478	          await deleteCheck(suiteId, check.id);
479	          message.success(`${check.name} deleted`);
480	          onChanged();
481	        } catch (err) {
482	          message.error(`Delete failed: ${err instanceof Error ? err.message : 'unknown error'}`);
483	          throw err; // keep the confirm modal open on failure
484	        }
485	      },
486	    });
487	  };
488	
489	  if (state.status === 'loading') {
490	    return <Spin tip="Loading checks…" />;
491	  }
492	  if (state.status === 'error') {
493	    return <Alert type="error" showIcon title="Failed to load checks" description={state.error} />;
494	  }
495	  const checks = state.data;
496	  return (
497	    <Card
498	      size="small"
499	      title={`Checks (${checks.length})`}
500	      extra={
501	        <Button type="primary" size="small" onClick={onAdd}>
502	          Add check
503	        </Button>
504	      }
505	    >
506	      {checks.length === 0 ? (
507	        <Empty
508	          image={Empty.PRESENTED_IMAGE_SIMPLE}
509	          description="No checks yet — add one to start."
510	        />
511	      ) : (
512	        <List
513	          dataSource={checks}
514	          renderItem={(check) => (
515	            <List.Item
516	              actions={[
517	                <Button key="edit" type="link" size="small" onClick={() => onEdit(check)}>
518	                  Edit
519	                </Button>,
520	                <Button
521	                  key="delete"
522	                  type="link"
523	                  size="small"
524	                  danger
525	                  onClick={() => onDelete(check)}
526	                >
527	                  Delete
528	                </Button>,
529	              ]}
530	            >
531	              <Flex vertical gap={2}>
532	                <Typography.Text strong>{check.name}</Typography.Text>
533	                <Typography.Text type="secondary" style={{ fontSize: 12 }}>
534	                  {check.expectation_type}
535	                </Typography.Text>
536	              </Flex>
537	            </List.Item>
538	          )}
539	        />
540	      )}
541	    </Card>
542	  );
543	}
